'use client';
import { useStore } from '../app/lib/';
import ProfileCard from '../components/ProfileCard';
import { format } from 'date-fns';
import { ArrowUp, ArrowDown, Gift, Users } from 'lucide-react';
import { bn } from 'date-fns/locale/bn';

export default function Home() {
  const { netBalance, totalDonation, totalExpense, members, transactions } = useStore();

  // সেফটি চেক
  const safeTransactions = Array.isArray(transactions) ? transactions : [];
  const recent = safeTransactions.slice(0, 5).sort((a, b) => new Date(b.date || 0) - new Date(a.date || 0));

  // দানকারীদের রেকর্ড (case-insensitive নাম মিলানো)
  const donorsWithRecords = (members || []).map(m => {
    const donations = safeTransactions.filter(
      t => t?.type === 'donation' && t?.donorName?.trim().toLowerCase() === m?.name?.trim().toLowerCase()
    );
    return {
      ...m,
      donations,
      totalGiven: donations.reduce((sum, d) => sum + (Number(d?.amount) || 0), 0)
    };
  }).filter(m => m.donations.length > 0);

  // গ্রহীতাদের রেকর্ড
  const receiversWithRecords = (members || []).map(m => {
    const received = safeTransactions.filter(
      t => t?.type === 'donation' && t?.receiverName?.trim().toLowerCase() === m?.name?.trim().toLowerCase()
    );
    return {
      ...m,
      received,
      totalReceived: received.reduce((sum, d) => sum + (Number(d?.amount) || 0), 0)
    };
  }).filter(m => m.received.length > 0);

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-emerald-700 text-white p-5 sticky top-0 z-50 shadow-lg">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-3xl font-bold flex items-center gap-3">
            গ্রুপ ফান্ড <span className="text-4xl">💰</span>
          </h1>
          <div className="flex gap-8 text-lg">
            <a href="/" className="hover:underline">হোম</a>
            <a href="/members" className="hover:underline">সদস্য</a>
            <a href="/dashboard" className="hover:underline">ড্যাশবোর্ড</a>
          </div>
        </div>
      </nav>

      <div className="max-w-7xl mx-auto p-6 md:p-10">
        <div className="bg-gradient-to-r from-emerald-600 to-teal-600 text-white rounded-3xl shadow-2xl p-12 text-center mb-12">
          <p className="text-xl opacity-90">মোট নেট ব্যালেন্স</p>
          <p className="text-7xl md:text-8xl font-extrabold mt-4">
            ৳ {(netBalance ?? 0).toLocaleString('bn-BD')}
          </p>
        </div>

        <div className="grid grid-cols-2 lg:grid-cols-4 gap-6 mb-12">
          <StatCard icon={<ArrowUp />} title="মোট দান" value={totalDonation ?? 0} color="emerald" />
          <StatCard icon={<ArrowDown />} title="মোট খরচ" value={totalExpense ?? 0} color="red" />
          <StatCard icon={<Gift />} title="মোট লেনদেন" value={safeTransactions.length ?? 0} color="purple" />
          <StatCard icon={<Users />} title="মোট সদস্য" value={(members || []).length ?? 0} color="blue" />
        </div>

        <h2 className="text-4xl font-bold mb-8 text-gray-800">সাম্প্রতিক লেনদেন</h2>
        <div className="bg-white rounded-3xl shadow-xl overflow-hidden mb-12">
          {recent.length === 0 ? (
            <p className="text-center py-16 text-gray-500 text-xl">কোনো লেনদেন হয়নি এখনো</p>
          ) : (
            recent.map(t => (
              <div key={t?.id || Math.random()} className="flex flex-col md:flex-row justify-between items-start md:items-center p-6 border-b last:border-0 hover:bg-gray-50 transition">
                <div>
                  <p className="font-semibold text-lg">{t?.description || 'বিবরণ নেই'}</p>
                  <p className="text-sm text-gray-500 mt-1">
                    {t?.date ? format(new Date(t.date), 'dd MMMM yyyy', { locale: bn }) : 'তারিখ নেই'}
                  </p>
                </div>
                <p className={`font-bold text-xl mt-3 md:mt-0 ${t?.type === 'donation' ? 'text-indigo-600' : 'text-red-600'}`}>
                  {t?.type === 'donation' ? '+' : '-'} ৳ {(t?.amount ?? 0).toLocaleString('bn-BD')}
                </p>
              </div>
            ))
          )}
        </div>

        <h2 className="text-4xl font-bold mb-8 text-gray-800">সদস্যদের অবদান</h2>
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-16">
          {(members || []).length === 0 ? (
            <p className="col-span-full text-center py-16 text-gray-600 text-xl">
              কোনো সদস্য যোগ করা হয়নি। ড্যাশবোর্ডে গিয়ে যোগ করুন।
            </p>
          ) : (
            (members || []).map(m => <ProfileCard key={m?.id || Math.random()} member={m} />)
          )}
        </div>

        {/* দানকারীদের রেকর্ড */}
        <h2 className="text-4xl font-bold mb-8 text-indigo-800">দানকারীদের রেকর্ড (কে কাকে দান করেছে)</h2>
        {donorsWithRecords.length === 0 ? (
          <div className="bg-white rounded-3xl p-10 text-center shadow-xl mb-16">
            <p className="text-2xl text-gray-600">এখনো কোনো দানকারী নেই</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 mb-16">
            {donorsWithRecords.map(donor => (
              <div key={donor?.id || Math.random()} className="bg-white rounded-3xl shadow-xl p-8 hover:shadow-2xl transition">
                <div className="flex items-center gap-6 mb-6">
                  <div className="relative w-24 h-24 flex-shrink-0">
                    <Image 
                      src={donor.avatar || 'https://i.pravatar.cc/150?u=default'} 
                      alt={donor.name || 'দানকারী'} 
                      fill 
                      className="rounded-full object-cover border-4 border-indigo-300" 
                    />
                  </div>
                  <div>
                    <h3 className="text-2xl font-bold text-indigo-900">{donor.name || 'নামহীন'}</h3>
                    <p className="text-gray-700">মোট দান: {donor.donations.length} বার</p>
                  </div>
                </div>

                <div className="space-y-4">
                  {donor.donations.map(d => (
                    <div key={d?.id || Math.random()} className="bg-indigo-50 p-5 rounded-2xl">
                      <p className="font-semibold text-lg">→ {d?.receiverName || 'অজ্ঞাত'}</p>
                      <p className="text-indigo-700 font-bold text-xl mt-1">
                        ৳ {(d?.amount ?? 0).toLocaleString('bn-BD')}
                      </p>
                      <p className="text-gray-700 mt-1">{d?.reason || 'কারণ উল্লেখ নেই'}</p>
                      <p className="text-sm text-gray-500 mt-2">
                        {d?.date ? format(new Date(d.date), 'dd MMM yyyy', { locale: bn }) : 'তারিখ নেই'}
                      </p>
                    </div>
                  ))}
                </div>

                <p className="text-right mt-6 font-bold text-indigo-800 text-xl">
                  মোট দান: ৳ {donor.totalGiven.toLocaleString('bn-BD')}
                </p>
              </div>
            ))}
          </div>
        )}

        {/* গ্রহীতাদের রেকর্ড */}
        <h2 className="text-4xl font-bold mb-8 text-blue-800">গ্রহীতাদের রেকর্ড (কার কাছ থেকে কত পেয়েছে)</h2>
        {receiversWithRecords.length === 0 ? (
          <div className="bg-white rounded-3xl p-10 text-center shadow-xl">
            <p className="text-2xl text-gray-600">এখনো কোনো গ্রহীতা নেই</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {receiversWithRecords.map(receiver => (
              <div key={receiver?.id || Math.random()} className="bg-white rounded-3xl shadow-xl p-8 hover:shadow-2xl transition">
                <div className="flex items-center gap-6 mb-6">
                  <div className="relative w-24 h-24 flex-shrink-0">
                    <Image 
                      src={receiver.avatar || 'https://i.pravatar.cc/150?u=default'} 
                      alt={receiver.name || 'গ্রহীতা'} 
                      fill 
                      className="rounded-full object-cover border-4 border-blue-300" 
                    />
                  </div>
                  <div>
                    <h3 className="text-2xl font-bold text-blue-900">{receiver.name || 'নামহীন'}</h3>
                    <p className="text-gray-700">মোট পেয়েছে: {receiver.received.length} বার</p>
                  </div>
                </div>

                <div className="space-y-4">
                  {receiver.received.map(d => (
                    <div key={d?.id || Math.random()} className="bg-blue-50 p-5 rounded-2xl">
                      <p className="font-semibold text-lg">← {d?.donorName || 'অজ্ঞাত'}</p>
                      <p className="text-blue-700 font-bold text-xl mt-1">
                        ৳ {(d?.amount ?? 0).toLocaleString('bn-BD')}
                      </p>
                      <p className="text-gray-700 mt-1">{d?.reason || 'কারণ উল্লেখ নেই'}</p>
                      <p className="text-sm text-gray-500 mt-2">
                        {d?.date ? format(new Date(d.date), 'dd MMM yyyy', { locale: bn }) : 'তারিখ নেই'}
                      </p>
                    </div>
                  ))}
                </div>

                <p className="text-right mt-6 font-bold text-blue-800 text-xl">
                  মোট গ্রহণ: ৳ {receiver.totalReceived.toLocaleString('bn-BD')}
                </p>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

function StatCard({ icon, title, value, color }) {
  return (
    <div className="bg-white p-6 rounded-2xl shadow-lg text-center border-t-4 border-gray-200 hover:border-indigo-500 transition">
      <div className={`w-14 h-14 mx-auto mb-4 rounded-full flex items-center justify-center bg-${color}-100 text-${color}-600`}>
        {icon}
      </div>
      <p className="text-4xl font-bold text-gray-800">{(value ?? 0).toLocaleString('bn-BD')}</p>
      <p className="text-gray-600 mt-2">{title}</p>
    </div>
  );
}